const records = $input.first().json.records || [];
const token = $('Store token').first().json._umami_token;

const now = Date.now();
const DAY = 24 * 60 * 60 * 1000;

return records.map(r => ({
  json: {
    ...r.fields,
    _airtable_id: r.id,
    _umami_token: token,
    _thisStart:  now - 7  * DAY,
    _thisEnd:    now,
    _priorStart: now - 14 * DAY,
    _priorEnd:   now - 7  * DAY
  }
}));

const client = $('Loop each client').first().json;
const cfg    = $('Config').first().json;

const allItems = $input.all().map(i => i.json);

const statsItems  = allItems.filter(i => i.visitors !== undefined && i.x === undefined && !Array.isArray(i));
const metricItems = allItems.filter(i => i.x !== undefined && i.y !== undefined);

const cw = statsItems[0] || {};
const pw = statsItems[1] || {};

const topPagesRaw = metricItems.filter(i => String(i.x).startsWith('/'));
const sourcesRaw  = metricItems.filter(i => !String(i.x).startsWith('/'));

function parseStats(raw) {
  const v = (field) => (field && typeof field === 'object') ? (field.value || 0) : (field || 0);
  const visits    = v(raw.visits);
  const bounces   = v(raw.bounces);
  const totaltime = v(raw.totaltime);
  return {
    visitors:       v(raw.visitors),
    pageviews:      v(raw.pageviews),
    visits,
    bounce_rate:    visits > 0 ? Math.round((bounces / visits) * 100) : 0,
    visit_duration: visits > 0 ? Math.round(totaltime / visits) : 0
  };
}

const curr  = parseStats(cw);
const prior = parseStats(pw);

const topPages = topPagesRaw.map(p => ({ page: p.x, visitors: p.y }));
const sources  = sourcesRaw.map(s => ({ source: s.x || 'Direct', visitors: s.y }));

function wow(c, p) {
  if (!p || p === 0) return { value: c, prior: 0, pct: 0, arrow: '–' };
  const pct = parseFloat(((c - p) / p * 100).toFixed(1));
  return { value: c, prior: p, pct, arrow: pct >= 0 ? '▲' : '▼' };
}

const vWow = wow(curr.visitors,       prior.visitors);
const pWow = wow(curr.pageviews,      prior.pageviews);
const bWow = wow(curr.bounce_rate,    prior.bounce_rate);
const dWow = wow(curr.visit_duration, prior.visit_duration);

const googleSrc       = sources.find(s => /google/i.test(s.source));
const organicVisitors = googleSrc ? googleSrc.visitors : 0;
const organicPct      = curr.visitors > 0 ? ((organicVisitors / curr.visitors) * 100).toFixed(1) : '0.0';

const pagesTable   = topPages.slice(0, 15).map(p => `  ${String(p.page).padEnd(40)} ${String(p.visitors).padStart(6)} visitors`).join('\n');
const sourcesTable = sources.map(s => `  ${String(s.source).padEnd(25)} ${s.visitors} visitors`).join('\n');

const now     = new Date();
const weekAgo = new Date(now - 7 * 24 * 60 * 60 * 1000);
const fmt     = d => d.toISOString().split('T')[0];
const period  = `${fmt(weekAgo)} to ${fmt(now)}`;

const historyCtx = client.history_summary ? `\nHISTORY (prior 3 weeks):\n${client.history_summary}\n` : '';

const langMap = {
  'en':          'Write in English.',
  'bs-latin':    'Write in Bosnian (Latin script). Keep technical SEO terms in English.',
  'sr-latin':    'Write in Serbian (Latin script). Keep technical SEO terms in English.',
  'sr-cyrillic': 'Write in Serbian (Cyrillic). Keep technical SEO terms in English.',
  'hr':          'Write in Croatian. Keep technical SEO terms in English.',
  'mk':          'Write in Macedonian. Keep technical SEO terms in English.'
};
const langInstruction = langMap[client.language || cfg.DEFAULT_LANGUAGE] || langMap['en'];

const systemPrompt = `You are a senior SEO and AIO (AI-search optimisation) analyst producing weekly reports for SMBs.

Rules:
- Ground every recommendation in the provided data. Never invent metrics.
- Prioritise by impact-vs-effort (quick wins first).
- Be specific: name the page, the metric. No generic advice.
- AIO = optimising for Google AI Overviews, ChatGPT, Perplexity. Flag content at risk.
- ${langInstruction}

Output exactly these sections in order, using these exact labels:
1. WEEKLY SUMMARY — 3 sentences, headline numbers
2. TOP 3 WINS — what worked and why
3. TOP 3 ISSUES — what needs attention with specific data
4. SEO RECOMMENDATIONS — 3-5 prioritised actions, each tagged LOW/MED/HIGH effort
5. AIO RECOMMENDATIONS — 2-3 AI-search visibility actions
6. QUICK WIN — one specific action completable in under 2 hours`;

const userMessage = `SITE: ${client.site_name} (${client.umami_site_id})
PERIOD: ${period}

HEADLINE METRICS:
  Visitors:    ${vWow.value} (${vWow.arrow}${Math.abs(vWow.pct)}% vs prior week, was ${vWow.prior})
  Pageviews:   ${pWow.value} (${pWow.arrow}${Math.abs(pWow.pct)}%)
  Bounce rate: ${curr.bounce_rate}% (${bWow.arrow}${Math.abs(bWow.pct)}%)
  Avg session: ${curr.visit_duration}s (${dWow.arrow}${Math.abs(dWow.pct)}%)

ORGANIC (Google): ${organicVisitors} visitors (${organicPct}% of total)

TRAFFIC SOURCES:
${sourcesTable || '  No data'}

TOP PAGES:
${pagesTable || '  No data'}${historyCtx}`;

return [{ json: {
  client,
  systemPrompt,
  userMessage,
  cfg,
  meta: {
    visitors:         vWow.value,
    visitors_wow:     vWow.pct,
    pageviews:        pWow.value,
    bounce_rate:      curr.bounce_rate,
    organic_visitors: organicVisitors,
    period
  }
}}];

const client = $('Format data + build AI prompt').item.json.client;
const meta   = $('Format data + build AI prompt').item.json.meta;
const cfg    = $('Format data + build AI prompt').item.json.cfg;
const aiText = $json.choices[0].message.content;

const quickWinMatch = aiText.match(/QUICK WIN[:\s]*([\s\S]*?)(?=\n[A-Z]{2,}|$)/i);
const quickWin = quickWinMatch ? quickWinMatch[1].trim() : 'See full report for this week\'s quick win.';

const wowSign  = meta.visitors_wow >= 0 ? '+' : '';
const wowEmoji = meta.visitors_wow >= 0 ? '📈' : '📉';

const htmlBody = aiText.split('\n').map(line => {
  const t = line.trim();
  if (/^(WEEKLY SUMMARY|TOP 3 WINS|TOP 3 ISSUES|SEO RECOMMENDATIONS|AIO RECOMMENDATIONS|QUICK WIN)/i.test(t))
    return `<h3 style="color:#1a1a2e;margin:24px 0 8px;font-size:15px;font-weight:600;border-bottom:1px solid #e5e7eb;padding-bottom:6px">${t}</h3>`;
  if (t.startsWith('-') || /^\d+\./.test(t))
    return `<li style="margin:4px 0;color:#374151;line-height:1.6">${t.replace(/^[-\d.]+\s*/, '')}</li>`;
  if (t === '') return '<br>';
  return `<p style="margin:4px 0;color:#374151;line-height:1.6">${t}</p>`;
}).join('\n');

const slackBlocks = {
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: `${wowEmoji} Weekly SEO Report — ${client.site_name}`, emoji: true } },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Visitors*\n${meta.visitors} (${wowSign}${meta.visitors_wow}%)` },
        { type: 'mrkdwn', text: `*Organic*\n${meta.organic_visitors}` },
        { type: 'mrkdwn', text: `*Bounce Rate*\n${meta.bounce_rate}%` },
        { type: 'mrkdwn', text: `*Period*\n${meta.period}` }
      ]
    },
    { type: 'divider' },
    { type: 'section', text: { type: 'mrkdwn', text: `⚡ *This week's quick win*\n${quickWin}` } },
    { type: 'context', elements: [{ type: 'mrkdwn', text: 'Full report sent to your email.' }] }
  ]
};

const historySummary = `Week ${meta.period}: ${meta.visitors} visitors (${wowSign}${meta.visitors_wow}% WoW), ${meta.organic_visitors} organic, bounce rate ${meta.bounce_rate}%.`;

return [{ json: { client, meta, cfg, aiText, htmlBody, quickWin, slackBlocks, historySummary } }];
